    local function D(s)
        local b = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/"
        s = s:gsub("[^" .. b .. "=]", "")
        local res = ""
        local data = {}
        for i = 1, #s do data[i] = b:find(s:sub(i,i)) - 1 end
        for i = 1, #data, 4 do
            local n = (data[i] << 18) | (data[i+1] << 12) | ((data[i+2] or 0) << 6) | (data[i+3] or 0)
            res = res .. string.char((n >> 16) & 255)
            if data[i+2] then res = res .. string.char((n >> 8) & 255) end
            if data[i+3] then res = res .. string.char(n & 255) end
        end
        local rotated = ""
        for i = 1, #res do
            rotated = rotated .. string.char((res:byte(i) - 13 + 256) % 256)
        end
        return rotated
    end
    local source = ""
    for i = 1, #L do source = source .. D(L[i]) .. "\n" end
    local f, e = loadstring(source)
    if not f then error(e) end
    return f(...)
end)(...)
